q13 = 8 + 6*sin(trel3);

q14 = .3*sin(trel2);
q15 = .2*cos(trel3) ;
q16 = 6 + 3*sin(trel1);

q17 = .3*sin(trel4);
q18 = .3*cos(trel2);
q19 = 3 + sin(trel3);

trot = trel1/2;
trot = index2*6.28/4;
q5 = cos(trot);
q6 = sin(trot);
q7 = -q6;
q8 = q5;

